%[text] # Low code time series and geospatial data handling, analysis and visualization
%[text] ## Download data from Kaggle: [https://www.kaggle.com/datasets/decide-soluciones/air-quality-madrid](https://www.kaggle.com/datasets/decide-soluciones/air-quality-madrid) 
%[text] - madrid\_2018.csv
%[text] - stations.csv \
%%
%[text] ## Use the Import Data App to 
%[text] ### import "madrid\_2018.csv", then preview the File
% How would you begin importing this file?
stations = importAirfile('stations.csv');

%% Import data from text file
% Script for importing data from the following text file:
%
%    filename: C:\Users\lsammon\OneDrive - MathWorks\Documents\MATLAB\4_Seminars\NOAA boulder2026\Madrid_Air_Quality-main\madrid_2018.csv
%
% Auto-generated by MATLAB on 17-Jun-2026 10:06:54

%% Set up the Import Options and import the data
opts = delimitedTextImportOptions("NumVariables", 16);

% Specify range and delimiter
opts.DataLines = [2, Inf];
opts.Delimiter = ",";

% Specify column names and types
opts.VariableNames = ["date", "BEN", "CH4", "CO", "EBE", "NMHC", "NO", "NO_2", "NOx", "O_3", "PM10", "PM25", "SO_2", "TCH", "TOL", "station"];
opts.VariableTypes = ["datetime", "double", "double", "double", "double", "double", "double", "double", "double", "double", "double", "double", "double", "double", "double", "double"];

% Specify file level properties
opts.ExtraColumnsRule = "ignore";
opts.EmptyLineRule = "read";

% Specify variable properties
opts = setvaropts(opts, "date", "InputFormat", "yyyy-MM-dd HH:mm:ss", "DatetimeFormat", "preserveinput");

% Import the data
madrid_2018 = readtimetable("Madrid_Air_Quality-main\madrid_2018.csv", opts, "RowTimes", "date");


%% Clear temporary variables
clear opts

% What if you want to sort the rows interactively





%%
lat = 40; %[control:spinner:4129]{"position":[7,9]}

lon = 1; %[control:spinner:771d]{"position":[7,8]}


figure
geoscatter(lat,lon)
geobasemap("colorterrain")



%%
%[text] ## Unstack Table Variable
% unstack data from BEN in madrid into multiple variables

% Unstack variables %[task:6326]
unstackedTable = unstack(madrid,"BEN","station",AggregationFunction=@mean, ...
    VariableNamingRule="preserve") %[task:6326]
%%
%[text] ## Clean Missing Data
% Fill in the missing data in the madrid NO2 via the moving median method

% Fill missing data %[task:7236]
[cleanedData,missingIndices] = fillmissing(madrid_2018.NO_2,"movmedian",5);

% Display results
figure

% Plot cleaned data
plot(cleanedData,SeriesIndex=1,LineWidth=1.5,DisplayName="Cleaned data")
hold on

% Plot filled missing entries
plot(find(missingIndices),cleanedData(missingIndices),".",MarkerSize=12, ...
    SeriesIndex=2,DisplayName="Filled missing entries")
title("Number of filled missing entries: " + nnz(missingIndices))

hold off
legend
clear missingIndices %[task:7236]
%%
%[text] ## Check out the stations location
%[text] ### import "stations.csv", then preview the File
%[text] Transform the "id" variable from *Double* to *String*


hold off
%%
%[text] ### Create a Plot - to plot the Stations on a map
% View the stations on a map
% Create geoscatter of stations.lat and stations.lon %[task:3edd]
S = geoscatter(stations.lat,stations.lon);

% Add title
title("stations.lat vs. stations.lon") %[task:3edd]
hold on
geobasemap('satellite')

ax = gca;
chart = ax.Children(1);
datatip(chart,40.5,-3.69);
%%
%[text] ## Change the geobasemap and fill the circles 
%[text] Ask [MATLAB GPT](https://chatgpt.com/g/g-QFTjbeK3U-matlab) or [MATLAB AI Chat Playground](https://uk.mathworks.com/matlabcentral/playground/new) to "change the format of degrees in the geographic plot"
%[text] (check the documentation!)

% Plot stations: marker size fixed, color shows elevation
% geoscatter(lat,lon,markerSize,color) — lat first, lon second
figure
geoscatter(stations.lat,stations.lon,20,stations.elevation)



